content.query:
let created = customMetrics
| where name == 'upload_sessions_created'
| where timestamp {TimeRange}
| summarize Created = sum(valueCount);
let abandoned = customMetrics
| where name == 'upload_session_abandoned'
| where timestamp {TimeRange}
| summarize Abandoned = sum(valueCount);
let errors = customMetrics
| where name == 'upload_errors'
| where timestamp {TimeRange}
| summarize Errors = sum(valueCount);
created | extend Abandoned = toscalar(abandoned | project Abandoned), Errors = toscalar(errors | project Errors)
| extend Confirmed = Created - Abandoned
| project Created, Confirmed, Abandoned, Errors
